def print_map(karta):
    print("\033[H\033[J", end="")
    for y in range(len(karta)):
        print("")
        for x in range(len(karta[y])):
            print(karta[y][x].map_icon, end=" ")
    print("")

def check_collision(karta, delta_x, delta_y, player):
    proceed = True

    #lista ut vad man gått in i
    check_x = player.x + delta_x
    check_y = player.y + delta_y
    entity = karta[check_y][check_x]

    if entity.name == "lich":
        print("You approach your final battle with the lich, the master of this dungeon")
        proceed, player = start_battle(karta[check_y][check_x], player)
        print("Congratulations! you beat the game :)")
        exit()

    #om det är en fiende: starta en fight
    if entity.entity_type == "enemy":
        proceed, player = start_battle(karta[check_y][check_x], player)

    #om det är en fallucka: gå till nästa våning
    if entity.name == "trapdoor":
        karta, player = move_to_next_floor(player)
        print("You go down the stairs to the next floor")
        input("Press enter to continue")

    #Om det är en kista: skaffa en item
    if entity.entity_type == "chest":
        if entity.name == "1":
            loot_table = (items.leather_cap, items.leather_pants, items.leather_tunic, items.shield)
        if entity.name == "2":
            loot_table = (items.broadsword, items.tower_shield)
        if entity.name == "3":
            loot_table = (items.iron_chestplate, items.tower_shield, items.iron_helmet, items.iron_leggings)
        reward = random.choice(loot_table)
        print(f"You open the chest and find: {reward.name}")
        player.inventory.append(reward)
        input("Press enter to continue")
        
    return(proceed, karta, player)

def move(karta, riktning, player):
    delta_x = 0
    delta_y = 0
    if riktning == "w":
        delta_y = -1
        delta_x = 0
    if riktning == "a":
        delta_y = 0
        delta_x = -1
    if riktning == "s":
        delta_y = 1
        delta_x = 0
    if riktning == "d":
        delta_y = 0
        delta_x = 1
    proceed, karta, player = check_collision(karta, delta_x, delta_y, player)
    if proceed and not karta[player.y+delta_y][player.x+delta_x].entity_type == "wall":
        karta[player.y+delta_y][player.x+delta_x] = player
        karta[player.y][player.x] = stats.empty_tile
        player.y += delta_y
        player.x += delta_x
    return(karta, player)

def move_to_next_floor(player):
    global map_index
    map_index += 1
    karta = map_list[map_index]
    for y in range(len(karta)):
        for x in range(len(karta[y])):
            if karta[y][x].name == "player_placeholder":
                player.x = x
                player.y = y
    return(karta, player)